import React from "react";
import styles from "./JsonViewer.module.css";

export interface JsonViewerProps {
  value?: string;
  readOnly?: boolean;
  /** Editor height in px */
  height?: number;
  children?: React.ReactNode;
  onChange?: (event: React.ChangeEvent<HTMLInputElement>) => void;
}

/**
 * Read-only JSON tree viewer
 * @generated by Component Forge — edit schema and re-run forge generate
 */
export function JsonViewer({ value = "", readOnly = false, height = 320, children, onChange }: JsonViewerProps) {

  const inputId = React.useId();
  const errorId = `${inputId}-error`;
  return (
    <div className={styles.wrapper} data-testid="json-viewer">
      
      <input
        id={inputId}
        type="number"
        className={[styles.root].filter(Boolean).join(" ")}
        placeholder={placeholder}
        defaultValue={value}
        disabled={disabled}
        required={required}
        aria-required={required || undefined}
        onChange={onChange}
        onBlur={onBlur}
        aria-invalid={error ? true : undefined}
        aria-describedby={error ? errorId : undefined}
      />
      {error && (
        <span id={errorId} className={styles.error} role="alert">
          {error}
        </span>
      )}
    </div>
  );
}

JsonViewer.displayName = "JsonViewer";
